                result.AllowCookies = true;
                return result;
            }
            throw new System.InvalidOperationException(string.Format("No se pudo encontrar un punto de conexión con el nombre \"{0}\".", endpointConfiguration));
        }
        
        private static System.ServiceModel.EndpointAddress GetEndpointAddress(EndpointConfiguration endpointConfiguration)
        {
            if ((endpointConfiguration == EndpointConfiguration.BasicHttp))
            {
                return new System.ServiceModel.EndpointAddress("http://www.citram.es:8080/WSMultimodalInformation/MultimodalInformation.svc");
            }
            throw new System.InvalidOperationException(string.Format("No se pudo encontrar un punto de conexión con el nombre \"{0}\".", endpointConfiguration));
        }
        
        private static System.ServiceModel.Channels.Binding GetDefaultBinding()
        {
            return MultimodalInformationClient.GetBindingForEndpoint(EndpointConfiguration.BasicHttp);
        }
        
        private static System.ServiceModel.EndpointAddress GetDefaultEndpointAddress()
        {
            return MultimodalInformationClient.GetEndpointAddress(EndpointConfiguration.BasicHttp);
        }
        
        public enum EndpointConfiguration
        {
            
            BasicHttp,
        }
    }
